class Solution {
    public long maximumOr(int[] nums, int k) {
        long max = 0;
        for (int num : nums) {
            max |= num;
        }
        int[] counts = new int[20];
        for (int num : nums) {
            int i = 0;
            while (num > 0) {
                if ((num & 1) == 1) {
                    counts[i]++;
                }
                num >>= 1;
                i++;
            }
        }
        for (int i = 0; i <= k; i++) {
            long temp = max;
            for (int j = 0; j <= 19; j++) {
                if (counts[j] > 0 && k - i >= j) {
                    temp |= (1L << j);
                    counts[j]--;
                    k -= j;
                }
            }
            max = Math.max(max, temp);
        }
        return max;
    }
}
